-- Migration 22: The Forgiveness Profile (licensed EFMI, Enright et al.).
-- 30 items, 10 motivation subscales (3 each), 6-point scale. Results are not
-- emailed (email_link_only) — only a private link is sent.
alter table public.assessments add column if not exists email_link_only boolean not null default false;

insert into public.assessments (slug,name,subtitle,category,scale_min,scale_max,estimated_minutes,questions_per_page,sensitivity,email_link_only,is_published)
values ('forgiveness-profile','The Forgiveness Profile','What moves you toward forgiveness','personal',1,6,8,15,'standard',true,false)
on conflict (slug) do update set name=excluded.name, subtitle=excluded.subtitle, category=excluded.category,
  scale_min=excluded.scale_min, scale_max=excluded.scale_max, estimated_minutes=excluded.estimated_minutes,
  questions_per_page=excluded.questions_per_page, sensitivity=excluded.sensitivity, email_link_only=excluded.email_link_only;
delete from items where assessment_id=(select id from assessments where slug='forgiveness-profile');
with a as (select id from assessments where slug='forgiveness-profile')
insert into items (assessment_id,item_order,text,domain,is_scored,is_reverse_scored,item_type)
select a.id,v.ord,v.txt,v.dom,v.sc,v.rev,v.it::item_type from a,(values (1,'I do not want to displace my anger onto family members.','Protection for Others Inside the Family',true,false,'standard'),(2,'I want to be good to others, even those who hurt me.','Forgiveness as Good in Itself',true,false,'standard'),(3,'I want to honor my faith/philosophy of life.','Consistency with Your Beliefs',true,false,'standard'),(4,'I want the one who hurt me to have peace inside.','Healing for the Other',true,false,'standard'),(5,'I want to have peace inside of me.','Self-Healing',true,false,'standard'),(6,'I want my community to be peaceful.','Community Harmony',true,false,'standard'),(7,'I want to feel better.','Self-Healing',true,false,'standard'),(8,'I want to grow in character.','Self-Improvement',true,false,'standard'),(9,'My community will be better off if I am not overly angry.','Community Harmony',true,false,'standard'),(10,'I want the one who hurt me to feel better.','Healing for the Other',true,false,'standard'),(11,'I want to avoid adding conflict in the family.','Protection for Others Inside the Family',true,false,'standard'),(12,'I do not want my anger to spill over to friends.','Protection for Others Outside the Family',true,false,'standard'),(13,'I want to become an even better person.','Self-Improvement',true,false,'standard'),(14,'I want to improve my behavior.','Self-Improvement',true,false,'standard'),(15,'We could be reconciled.','Improved Relationship',true,false,'standard'),(16,'I want to help the one who offended me to grow in character.','Improvement for the Other',true,false,'standard'),(17,'I do not want to be angry with people at work or school.','Protection for Others Outside the Family',true,false,'standard'),(18,'I want to avoid making others miserable if I am miserable.','Protection for Others Outside the Family',true,false,'standard'),(19,'I want to see my community be as conflict-free as possible.','Community Harmony',true,false,'standard'),(20,'I want to be obedient to my faith/philosophy of life.','Consistency with Your Beliefs',true,false,'standard'),(21,'I want to have peace in the family.','Protection for Others Inside the Family',true,false,'standard'),(22,'My belief system encourages me to forgive.','Consistency with Your Beliefs',true,false,'standard'),(23,'We can be together again.','Improved Relationship',true,false,'standard'),(24,'I would like to mend the relationship.','Improved Relationship',true,false,'standard'),(25,'Forgiveness is good in and of itself.','Forgiveness as Good in Itself',true,false,'standard'),(26,'I want to help the one who hurt me to become an even better person.','Improvement for the Other',true,false,'standard'),(27,'I want to be free of resentment.','Self-Healing',true,false,'standard'),(28,'Forgiveness is an expression of love.','Forgiveness as Good in Itself',true,false,'standard'),(29,'I want the other person not to feel badly any more.','Healing for the Other',true,false,'standard'),(30,'I want the one who offended me to know goodness.','Improvement for the Other',true,false,'standard')) as v(ord,txt,dom,sc,rev,it);
